  const facts = yield* graphiti.searchFacts({
    query: params.query,
    maxFacts: params.maxFacts ?? 20,
  });

  return {
    facts: mapFactsToGraphFacts(facts),
    links: mapFactsToGraphLinks(facts),
  };
});

